--
-- Name: get_employee_payment_balance_by_date(date, character varying); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_employee_payment_balance_by_date(p_date date, p_warehouse_id character varying DEFAULT NULL::character varying) RETURNS TABLE(employee_id character varying, employee_name character varying, warehouse_id character varying, payment_total numeric, employee_balance numeric, total_amount numeric, description character varying)
    LANGUAGE plpgsql
    AS $$
BEGIN
    RETURN QUERY
    SELECT
        e.id AS employee_id,
        p_profile."name" AS employee_name,
        e.warehouse_id,
        COALESCE(pay_summary.payment_total, 0) AS payment_total,
        COALESCE(lb.last_balance_amount, 0) AS employee_balance,
        COALESCE(pay_summary.payment_total, 0) + COALESCE(lb.last_balance_amount, 0) AS total_amount,
        CAST(
            CASE
                WHEN COALESCE(pay_summary.payment_total, 0) + COALESCE(lb.last_balance_amount, 0) > 0
                THEN 'lebih setor'
                ELSE ''
            END AS varchar
        ) AS description
    FROM employee e
    LEFT JOIN profile p_profile
        ON e.profile_id = p_profile.id
    LEFT JOIN (
        SELECT operator_id, SUM(settlement_amount - amount) AS payment_total
        FROM payment
        WHERE registered::date = p_date
          AND status = 'SUCCESS'
        GROUP BY operator_id
    ) pay_summary
        ON pay_summary.operator_id = e.id
    LEFT JOIN (
        SELECT DISTINCT ON (holder_id) holder_id, balance AS last_balance_amount
        FROM balance
        ORDER BY holder_id, registered DESC
    ) lb
        ON lb.holder_id = e.id
    WHERE p_warehouse_id IS NULL OR e.warehouse_id = p_warehouse_id;
END;
$$;


ALTER FUNCTION public.get_employee_payment_balance_by_date(p_date date, p_warehouse_id character varying) OWNER TO postgres;

