-- Name: attendance_view; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.attendance_view AS
 SELECT a.id,
    a.employee_id,
    p.name AS employee_name,
    e.warehouse_id,
    pw.name AS warehouse_name,
    e.branch_id,
    pb.name AS branch_name,
    a.clock_in,
    a.clock_out,
    a.notes,
    a.registered,
    a.modificated,
    a.longitude_in,
    a.latitude_in,
    a.longitude_out,
    a.latitude_out
   FROM ((((((public.attendance a
     LEFT JOIN public.employee e ON (((a.employee_id)::text = (e.id)::text)))
     LEFT JOIN public.profile p ON (((e.profile_id)::text = (p.id)::text)))
     LEFT JOIN public.warehouse w ON (((e.warehouse_id)::text = (w.id)::text)))
     LEFT JOIN public.branch b ON (((e.branch_id)::text = (b.id)::text)))
     LEFT JOIN public.profile pw ON (((w.profile_id)::text = (p.id)::text)))
     LEFT JOIN public.profile pb ON (((b.profile_id)::text = (p.id)::text)));


