--
-- Name: bq_movement; Type: VIEW; Schema: public; Owner: seltrak
--

CREATE VIEW public.bq_movement AS
 SELECT im.id,
    to_char((t.registered AT TIME ZONE 'Asia/Jakarta'::text), 'YYYY/MM/DD HH24:MI:SS'::text) AS waktu,
    p4.name AS divisi,
    COALESCE(p.name, p2.name, p3.name) AS nama,
    'tunai'::text AS transaksi,
    to_char((t.registered AT TIME ZONE 'Asia/Jakarta'::text), 'YYYY/MM/DD'::text) AS tanggal,
    'OS'::text AS kategori,
    COALESCE(p5.name, p6.name, p7.name) AS toko,
    a.address AS alamat,
    concat(a.district, ', ', a.city, ', ', a.province) AS kecamatan,
    c.phone AS telp,
    ''::text AS catatan,
    p8.name AS produk,
    im.qty,
    im.price AS harga,
        CASE
            WHEN (im.price_base > im.price) THEN (im.price_base - im.price)
            ELSE (0)::numeric
        END AS diskon
   FROM ((((((((((((((((((public.inventory_movement im
     LEFT JOIN public.transaction t ON (((im.transaction_id)::text = (t.id)::text)))
     LEFT JOIN public.employee e ON (((t.source_id)::text = (e.id)::text)))
     LEFT JOIN public.profile p ON (((e.profile_id)::text = (p.id)::text)))
     LEFT JOIN public.branch b ON (((t.source_id)::text = (b.id)::text)))
     LEFT JOIN public.profile p2 ON (((b.profile_id)::text = (p2.id)::text)))
     LEFT JOIN public.warehouse w ON (((t.source_id)::text = (w.id)::text)))
     LEFT JOIN public.profile p3 ON (((w.profile_id)::text = (p3.id)::text)))
     LEFT JOIN public.warehouse w2 ON (((COALESCE(e.warehouse_id, b.warehouse_id, w.id))::text = (w2.id)::text)))
     LEFT JOIN public.profile p4 ON (((w2.profile_id)::text = (p4.id)::text)))
     LEFT JOIN public.employee e2 ON (((t.beneficiary_id)::text = (e2.id)::text)))
     LEFT JOIN public.profile p5 ON (((e2.profile_id)::text = (p5.id)::text)))
     LEFT JOIN public.branch b2 ON (((t.beneficiary_id)::text = (b2.id)::text)))
     LEFT JOIN public.profile p6 ON (((b2.profile_id)::text = (p6.id)::text)))
     LEFT JOIN public.warehouse w3 ON (((t.source_id)::text = (w3.id)::text)))
     LEFT JOIN public.profile p7 ON (((w3.profile_id)::text = (p7.id)::text)))
     LEFT JOIN public.address a ON (((COALESCE(p5.id, p6.id, p7.id))::text = (a.profile_id)::text)))
     LEFT JOIN public.contact c ON (((COALESCE(p5.id, p6.id, p7.id))::text = (c.profile_id)::text)))
     LEFT JOIN public.product p8 ON (((im.product_id)::text = (p8.id)::text)))
  WHERE ((t.type)::text <> ALL (ARRAY[('RESTOCK'::character varying)::text, ('SS'::character varying)::text, ('RU'::character varying)::text]));


ALTER VIEW public.bq_movement OWNER TO seltrak;

