    p2.name AS divisi,
    p.name AS nama,
    'tunai'::text AS transaksi,
    to_char((t.registered AT TIME ZONE 'Asia/Jakarta'::text), 'YYYY/MM/DD'::text) AS tanggal,
    'SA'::text AS kategori,
    p3.name AS toko,
    a.address AS alamat,
    concat(a.district, ', ', a.city, ', ', a.province) AS kecamatan,
    c2.phone AS telp,
    ''::text AS catatan,
    p4.id AS product_id,
    p4.name AS produk,
    im.qty,
    im.price AS harga,
        CASE
            WHEN (im.price_base > im.price) THEN (im.price_base - im.price)
            ELSE (0)::numeric
        END AS diskon
   FROM ((((((((((public.inventory_movement im
     LEFT JOIN public.transaction t ON (((im.transaction_id)::text = (t.id)::text)))
     LEFT JOIN public.employee e ON (((t.operator_id)::text = (e.id)::text)))
     LEFT JOIN public.profile p ON (((e.profile_id)::text = (p.id)::text)))
     LEFT JOIN public.warehouse w ON (((e.warehouse_id)::text = (w.id)::text)))
     LEFT JOIN public.profile p2 ON (((w.profile_id)::text = (p2.id)::text)))
     LEFT JOIN public.customer c ON (((t.beneficiary_id)::text = (c.id)::text)))
     LEFT JOIN public.profile p3 ON (((c.profile_id)::text = (p3.id)::text)))
     LEFT JOIN public.address a ON (((p3.id)::text = (a.profile_id)::text)))
     LEFT JOIN public.contact c2 ON (((p3.id)::text = (c2.profile_id)::text)))
     LEFT JOIN public.product p4 ON (((im.product_id)::text = (p4.id)::text)))
  WHERE (((t.type)::text = 'SS'::text) AND ((t.status)::text = 'SUCCESS'::text))
  ORDER BY t.registered DESC;


