--
-- Name: deposit_summary_view; Type: VIEW; Schema: public; Owner: seltrak
--

CREATE VIEW public.deposit_summary_view AS
 SELECT w.id AS employee_id,
    w.id AS warehouse_id,
    p_wh.name AS employee_name,
    COALESCE(sum((d.amount - d.settlement_amount)), (0)::numeric) AS outstanding,
    (0)::numeric AS balance
   FROM ((public.warehouse w
     LEFT JOIN public.profile p_wh ON (((w.profile_id)::text = (p_wh.id)::text)))
     LEFT JOIN public.deposit d ON (((d.beneficiary_id)::text = (w.id)::text)))
  WHERE ((d.status)::text <> ALL ((ARRAY['REJECT'::character varying, 'REQUEST'::character varying])::text[]))
  GROUP BY w.id, p_wh.name
UNION ALL
 SELECT e.id AS employee_id,
    e.warehouse_id,
    p_profile.name AS employee_name,
    COALESCE(sum((p.amount - p.settlement_amount)), (0)::numeric) AS outstanding,
    COALESCE(b.balance, (0)::numeric) AS balance
   FROM ((((public.employee e
     LEFT JOIN public.profile p_profile ON (((e.profile_id)::text = (p_profile.id)::text)))
     LEFT JOIN public.payment p ON (((p.operator_id)::text = (e.id)::text)))
     LEFT JOIN public.balance b ON (((b.holder_id)::text = (e.id)::text)))
     LEFT JOIN public."user" u ON (((u.id)::text = (e.user_id)::text)))
  WHERE ((u.role)::text = ANY (ARRAY[('KORLAP'::character varying)::text, ('SALES'::character varying)::text]))
  GROUP BY e.id, e.warehouse_id, p_profile.name, b.balance;


ALTER VIEW public.deposit_summary_view OWNER TO seltrak;

