--
-- Name: employee_payment_balance_view; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.employee_payment_balance_view AS
 SELECT e.id AS employee_id,
    e.user_id,
    e.profile_id,
    e.warehouse_id,
    e.branch_id,
    COALESCE(sum((p.settlement_amount - p.amount)), (0)::numeric) AS payment_total,
    COALESCE(b.balance, (0)::numeric) AS balance,
    (COALESCE(sum((p.settlement_amount - p.amount)), (0)::numeric) + COALESCE(b.balance, (0)::numeric)) AS total_amount
   FROM ((public.employee e
     LEFT JOIN public.payment p ON (((p.operator_id)::text = (e.id)::text)))
     LEFT JOIN public.balance b ON (((b.holder_id)::text = (e.id)::text)))
  GROUP BY e.id, e.user_id, e.profile_id, e.warehouse_id, e.branch_id, b.balance;


