--
-- Name: employee_view; Type: VIEW; Schema: public; Owner: seltrak
--

CREATE VIEW public.employee_view AS
 SELECT e.id,
    e.status,
    e.registered,
    e.modificated,
    p.name,
    p.gender,
    u.username,
    u.role,
    w.id AS warehouse_id,
    pw.name AS warehouse_name,
    b.id AS branch_id,
    pb.name AS branch_name,
    c.email,
    c.phone,
    a.address,
    a.village,
    a.district,
    a.city,
    a.province,
    a.postal_code,
    a.latitude,
    a.longitude,
    a1.address AS residential_address,
    a1.village AS residential_village,
    a1.district AS residential_district,
    a1.city AS residential_city,
    a1.province AS residential_province,
    a1.postal_code AS residential_postal_code,
    a1.latitude AS residential_latitude,
    a1.longitude AS residential_longitude
   FROM (((((((((public.employee e
     LEFT JOIN public.profile p ON (((e.profile_id)::text = (p.id)::text)))
     LEFT JOIN public."user" u ON (((e.user_id)::text = (u.id)::text)))
     LEFT JOIN public.warehouse w ON (((e.warehouse_id)::text = (w.id)::text)))
     LEFT JOIN public.profile pw ON (((w.profile_id)::text = (pw.id)::text)))
     LEFT JOIN public.branch b ON (((e.branch_id)::text = (b.id)::text)))
     LEFT JOIN public.profile pb ON (((b.profile_id)::text = (pb.id)::text)))
     LEFT JOIN public.contact c ON (((c.profile_id)::text = (e.profile_id)::text)))
     LEFT JOIN public.address a ON ((((a.profile_id)::text = (e.profile_id)::text) AND ((a.type)::text = 'CARD'::text))))
     LEFT JOIN public.address a1 ON ((((a1.profile_id)::text = (e.profile_id)::text) AND ((a1.type)::text = 'RESIDENTIAL'::text))));


