--
-- Name: inventory_view; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.inventory_view AS
 SELECT i.id,
    i.product_id,
    p.name AS product_name,
    i.holder_id,
    pr.name AS holder_name,
    COALESCE(e.warehouse_id, b.warehouse_id) AS warehouse_id,
    e.branch_id,
    i.qty,
    p.unit,
    i.registered,
    i.modificated
   FROM (((((public.inventory i
     LEFT JOIN public.product p ON (((i.product_id)::text = (p.id)::text)))
     LEFT JOIN public.warehouse w ON ((((i.holder_id)::text = (w.id)::text) AND ((i.holder_type)::text = 'WAREHOUSE'::text))))
     LEFT JOIN public.branch b ON ((((i.holder_id)::text = (b.id)::text) AND ((i.holder_type)::text = 'BRANCH'::text))))
     LEFT JOIN public.employee e ON ((((i.holder_id)::text = (e.id)::text) AND ((i.holder_type)::text = 'SALES'::text))))
     LEFT JOIN public.profile pr ON (((pr.id)::text = (
        CASE
            WHEN ((i.holder_type)::text = 'WAREHOUSE'::text) THEN w.profile_id
            WHEN ((i.holder_type)::text = 'BRANCH'::text) THEN b.profile_id
            WHEN ((i.holder_type)::text = 'SALES'::text) THEN e.profile_id
            ELSE NULL::character varying
        END)::text)));


ALTER VIEW public.inventory_view OWNER TO postgres;

