--
-- Name: sales_target_daily_view; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.sales_target_daily_view AS
 SELECT warehouse_id,
    sum(payment_amount) AS payment_amount,
    date(registered) AS registered
   FROM public.transaction t
  WHERE (((type)::text = 'SS'::text) AND (EXTRACT(year FROM registered) = EXTRACT(year FROM CURRENT_DATE)) AND (EXTRACT(month FROM registered) = EXTRACT(month FROM CURRENT_DATE)) AND (EXTRACT(day FROM registered) = EXTRACT(day FROM CURRENT_DATE)))
  GROUP BY warehouse_id, (date(registered))
  ORDER BY (date(registered));


