--
-- Name: transaction_best_sales; Type: VIEW; Schema: public; Owner: seltrak
--

CREATE VIEW public.transaction_best_sales AS
 SELECT t.source_id,
    t.warehouse_id,
    t.total_amount,
    t.total_transaction,
    t.total_qty,
    t.rnk,
    p.name AS source_name
   FROM ((( SELECT t_1.source_id,
            t_1.warehouse_id,
            sum(t_1.payment_amount) AS total_amount,
            count(t_1.id) AS total_transaction,
            sum(im.qty) AS total_qty,
            rank() OVER (ORDER BY (sum(t_1.payment_amount)) DESC) AS rnk
           FROM (public.transaction t_1
             LEFT JOIN public.inventory_movement im ON (((t_1.id)::text = (im.transaction_id)::text)))
          WHERE (((t_1.type)::text = 'SS'::text) AND (((t_1.registered AT TIME ZONE 'Asia/Jakarta'::text))::date = (CURRENT_DATE AT TIME ZONE 'Asia/Jakarta'::text)))
          GROUP BY t_1.source_id, t_1.warehouse_id) t
     LEFT JOIN public.employee e ON (((t.source_id)::text = (e.id)::text)))
     LEFT JOIN public.profile p ON (((e.profile_id)::text = (p.id)::text)))
  WHERE (t.rnk = 1);


ALTER VIEW public.transaction_best_sales OWNER TO seltrak;

--
-- Name: transaction_chart; Type: VIEW; Schema: public; Owner: seltrak
--

CREATE VIEW public.transaction_chart AS
 SELECT 'W1'::text AS warehouse_id,
    date((registered AT TIME ZONE 'Asia/Jakarta'::text)) AS registered,
    count(id) AS total_transaction
   FROM public.transaction t
  WHERE (((type)::text = 'SS'::text) AND ((status)::text = 'SUCCESS'::text) AND (((registered AT TIME ZONE 'Asia/Jakarta'::text))::date >= ((CURRENT_DATE AT TIME ZONE 'Asia/Jakarta'::text) - '60 days'::interval)))
  GROUP BY warehouse_id, (date((registered AT TIME ZONE 'Asia/Jakarta'::text)))
  ORDER BY (date((registered AT TIME ZONE 'Asia/Jakarta'::text))) DESC;


ALTER VIEW public.transaction_chart OWNER TO seltrak;

--
-- Name: transaction_daily; Type: VIEW; Schema: public; Owner: seltrak
--

CREATE VIEW public.transaction_daily AS
 SELECT sum(payment_amount) AS total_amount,
    count(id) AS total_transaction,
    sum(( SELECT COALESCE(sum(im.qty), (0)::numeric) AS "coalesce"
           FROM public.inventory_movement im
          WHERE ((im.transaction_id)::text = (t.id)::text))) AS total_qty,
    ((registered AT TIME ZONE 'Asia/Jakarta'::text))::date AS registered
   FROM public.transaction t
  WHERE (((type)::text = 'SS'::text) AND ((registered AT TIME ZONE 'Asia/Jakarta'::text) >= (CURRENT_DATE - '1 day'::interval)) AND ((registered AT TIME ZONE 'Asia/Jakarta'::text) < (CURRENT_DATE + '1 day'::interval)))
  GROUP BY (((registered AT TIME ZONE 'Asia/Jakarta'::text))::date)
  ORDER BY (((registered AT TIME ZONE 'Asia/Jakarta'::text))::date) DESC;


ALTER VIEW public.transaction_daily OWNER TO seltrak;

--
-- Name: transaction_daily_branch; Type: VIEW; Schema: public; Owner: seltrak
--

CREATE VIEW public.transaction_daily_branch AS
 SELECT t.branch_id AS id,
    sum(t.payment_amount) AS total_amount,
    count(t.id) AS total_transaction,
    sum(COALESCE(im.total_qty, (0)::numeric)) AS total_qty,
    ((t.registered AT TIME ZONE 'Asia/Jakarta'::text))::date AS registered
   FROM (public.transaction t
     LEFT JOIN ( SELECT inventory_movement.transaction_id,
            sum(inventory_movement.qty) AS total_qty
           FROM public.inventory_movement
          GROUP BY inventory_movement.transaction_id) im ON (((im.transaction_id)::text = (t.id)::text)))
  WHERE (((t.type)::text = 'SS'::text) AND ((t.registered AT TIME ZONE 'Asia/Jakarta'::text) >= (CURRENT_DATE - '1 day'::interval)) AND ((t.registered AT TIME ZONE 'Asia/Jakarta'::text) < (CURRENT_DATE + '1 day'::interval)))
  GROUP BY t.branch_id, (((t.registered AT TIME ZONE 'Asia/Jakarta'::text))::date)
  ORDER BY (((t.registered AT TIME ZONE 'Asia/Jakarta'::text))::date) DESC;


ALTER VIEW public.transaction_daily_branch OWNER TO seltrak;

--
-- Name: transaction_daily_detail; Type: VIEW; Schema: public; Owner: seltrak
--

CREATE VIEW public.transaction_daily_detail AS
 SELECT im.id,
    p2.name AS employee_name,
    p.name AS product_name,
    im.qty,
    im.unit,
    im.qty_transaction,
    im.unit_transaction,
    (im.qty * im.price) AS payment_amount,
    ((t.registered AT TIME ZONE 'Asia/Jakarta'::text))::date AS registered,
    e.warehouse_id
   FROM ((((public.transaction t
     LEFT JOIN public.inventory_movement im ON (((t.id)::text = (im.transaction_id)::text)))
     LEFT JOIN public.product p ON (((im.product_id)::text = (p.id)::text)))
     LEFT JOIN public.employee e ON (((t.operator_id)::text = (e.id)::text)))
     LEFT JOIN public.profile p2 ON (((e.profile_id)::text = (p2.id)::text)))
  WHERE (((t.type)::text = 'SS'::text) AND ((t.status)::text = 'SUCCESS'::text) AND (((t.registered AT TIME ZONE 'Asia/Jakarta'::text))::date = ((CURRENT_TIMESTAMP AT TIME ZONE 'Asia/Jakarta'::text))::date))
  ORDER BY (((t.registered AT TIME ZONE 'Asia/Jakarta'::text))::date) DESC;


ALTER VIEW public.transaction_daily_detail OWNER TO seltrak;

--
-- Name: transaction_daily_sales; Type: VIEW; Schema: public; Owner: seltrak
--

CREATE VIEW public.transaction_daily_sales AS
 SELECT source_id AS id,
    sum(payment_amount) AS total_amount,
    count(id) AS total_transaction,
    sum(( SELECT COALESCE(sum(im.qty), (0)::numeric) AS "coalesce"
           FROM public.inventory_movement im
          WHERE ((im.transaction_id)::text = (t.id)::text))) AS total_qty,
    ((registered AT TIME ZONE 'Asia/Jakarta'::text))::date AS registered
   FROM public.transaction t
  WHERE (((type)::text = 'SS'::text) AND ((registered AT TIME ZONE 'Asia/Jakarta'::text) >= (CURRENT_DATE - '1 day'::interval)) AND ((registered AT TIME ZONE 'Asia/Jakarta'::text) < (CURRENT_DATE + '1 day'::interval)))
  GROUP BY source_id, (((registered AT TIME ZONE 'Asia/Jakarta'::text))::date)
  ORDER BY (((registered AT TIME ZONE 'Asia/Jakarta'::text))::date) DESC;


ALTER VIEW public.transaction_daily_sales OWNER TO seltrak;

--
-- Name: transaction_daily_warehouse; Type: VIEW; Schema: public; Owner: seltrak
--

CREATE VIEW public.transaction_daily_warehouse AS
 SELECT warehouse_id AS id,
    sum(payment_amount) AS total_amount,
    count(id) AS total_transaction,
    sum(( SELECT COALESCE(sum(im.qty), (0)::numeric) AS "coalesce"
           FROM public.inventory_movement im
          WHERE ((im.transaction_id)::text = (t.id)::text))) AS total_qty,
    ((registered AT TIME ZONE 'Asia/Jakarta'::text))::date AS registered
   FROM public.transaction t
  WHERE (((type)::text = 'SS'::text) AND ((registered AT TIME ZONE 'Asia/Jakarta'::text) >= (CURRENT_DATE - '1 day'::interval)) AND ((registered AT TIME ZONE 'Asia/Jakarta'::text) < (CURRENT_DATE + '1 day'::interval)))
  GROUP BY warehouse_id, (((registered AT TIME ZONE 'Asia/Jakarta'::text))::date)
  ORDER BY (((registered AT TIME ZONE 'Asia/Jakarta'::text))::date) DESC;


ALTER VIEW public.transaction_daily_warehouse OWNER TO seltrak;

--
-- Name: transaction_dashboard; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.transaction_dashboard AS
 SELECT im.transaction_id AS id,
    count(im.id) AS items,
    sum(im.qty) AS qty,
    c.id AS customer_id,
    pc.name AS customer,
    t.amount,
    e.id AS sales_id,
    p.name AS sales,
    t.branch_id,
    t.warehouse_id,
    t.status,
    t.registered
   FROM (((((public.inventory_movement im
     LEFT JOIN public.transaction t ON (((im.transaction_id)::text = (t.id)::text)))
     LEFT JOIN public.employee e ON (((t.source_id)::text = (e.id)::text)))
     LEFT JOIN public.profile p ON (((e.profile_id)::text = (p.id)::text)))
     LEFT JOIN public.customer c ON (((t.beneficiary_id)::text = (c.id)::text)))
     LEFT JOIN public.profile pc ON (((c.profile_id)::text = (pc.id)::text)))
  WHERE (((t.type)::text = 'SS'::text) AND (t.registered >= (CURRENT_DATE - '3 mons'::interval)))
  GROUP BY im.transaction_id, pc.name, t.amount, p.name, t.branch_id, t.warehouse_id, t.status, t.registered, c.id, e.id;


ALTER VIEW public.transaction_dashboard OWNER TO postgres;

--
-- Name: transaction_last_table; Type: VIEW; Schema: public; Owner: seltrak
--

CREATE VIEW public.transaction_last_table AS
 SELECT t.id,
    t.warehouse_id,
    t.amount,
    t.status,
    t.source_id,
    p.name AS source_name,
    t.beneficiary_id,
    pc.name AS beneficiary_name,
    t.registered,
    ( SELECT count(im.id) AS count
           FROM public.inventory_movement im
          WHERE ((im.transaction_id)::text = (t.id)::text)) AS items
   FROM ((((public.transaction t
     LEFT JOIN public.employee e ON (((t.source_id)::text = (e.id)::text)))
     LEFT JOIN public.profile p ON (((e.profile_id)::text = (p.id)::text)))
     LEFT JOIN public.customer c ON (((t.beneficiary_id)::text = (c.id)::text)))
     LEFT JOIN public.profile pc ON (((c.profile_id)::text = (pc.id)::text)))
  WHERE ((t.type)::text = 'SS'::text)
  ORDER BY t.registered DESC
 LIMIT 20;


ALTER VIEW public.transaction_last_table OWNER TO seltrak;

