--
-- Name: transaction_sales_view; Type: VIEW; Schema: public; Owner: seltrak
--

CREATE VIEW public.transaction_sales_view AS
 SELECT t.id,
    t.warehouse_id,
    t.type,
    t.status,
    t.source_id,
    p.name AS source_name,
    c.email AS source_email,
    c.phone AS source_phone,
    t.beneficiary_id,
    p2.name AS beneficiary_name,
    c3.email AS beneficiary_email,
    c3.phone AS beneficiary_phone,
    a.district AS beneficiary_district,
    a.city AS beneficiary_city,
    p3.amount,
    p3.settlement_amount,
    date(t.registered) AS registered,
    t.note,
    t.registered AS registered_datetime
   FROM (((((((((public.transaction t
     LEFT JOIN public.employee e ON (((t.source_id)::text = (e.id)::text)))
     LEFT JOIN public."user" u ON (((e.user_id)::text = (u.id)::text)))
     LEFT JOIN public.profile p ON (((e.profile_id)::text = (p.id)::text)))
     LEFT JOIN public.contact c ON (((p.id)::text = (c.profile_id)::text)))
     LEFT JOIN public.customer c2 ON (((t.beneficiary_id)::text = (c2.id)::text)))
     LEFT JOIN public.profile p2 ON (((c2.profile_id)::text = (p2.id)::text)))
     LEFT JOIN public.contact c3 ON (((p2.id)::text = (c3.profile_id)::text)))
     LEFT JOIN public.address a ON (((p2.id)::text = (a.profile_id)::text)))
     LEFT JOIN public.payment p3 ON (((t.id)::text = (p3.transaction_id)::text)))
  WHERE (((t.status)::text = 'SUCCESS'::text) AND ((t.type)::text = ANY (ARRAY['SS'::text, 'BPOB'::text, 'BPOW'::text, 'SPOS'::text, 'SPOB'::text])))
  ORDER BY t.registered;


ALTER VIEW public.transaction_sales_view OWNER TO seltrak;

--
-- Name: transaction_view; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.transaction_view AS
 SELECT t.id,
    t.operator_id,
    p.name AS operator_name,
    t.source_id,
    COALESCE(pss.name, pws.name, pbs.name, ps.name) AS source_name,
    t.beneficiary_id,
    COALESCE(pwb.name, pbb.name, pb.name, pc.name) AS beneficiary_name,
    t.branch_id,
    t.warehouse_id,
    t.type,
    t.status,
    (t.amount - (t.return_amount)::numeric) AS amount,
    (t.total_amount - (t.return_amount)::numeric) AS total_amount,
    t.payment_amount,
    t.return_amount,
    t.note,
    t.reference_id,
    t.registered
   FROM ((((((((((((((((((public.transaction t
     LEFT JOIN public.employee e ON (((t.operator_id)::text = (e.id)::text)))
     LEFT JOIN public.profile p ON (((e.profile_id)::text = (p.id)::text)))
     LEFT JOIN public.supplier ss ON (((t.source_id)::text = (ss.id)::text)))
     LEFT JOIN public.profile pss ON (((ss.profile_id)::text = (pss.id)::text)))
     LEFT JOIN public.warehouse ws ON (((t.source_id)::text = (ws.id)::text)))
     LEFT JOIN public.profile pws ON (((ws.profile_id)::text = (pws.id)::text)))
     LEFT JOIN public.branch bs ON (((t.source_id)::text = (bs.id)::text)))
     LEFT JOIN public.profile pbs ON (((bs.profile_id)::text = (pbs.id)::text)))
     LEFT JOIN public.employee es ON (((t.source_id)::text = (es.id)::text)))
     LEFT JOIN public.profile ps ON (((es.profile_id)::text = (ps.id)::text)))
     LEFT JOIN public.warehouse wb ON (((t.beneficiary_id)::text = (wb.id)::text)))
     LEFT JOIN public.profile pwb ON (((wb.profile_id)::text = (pwb.id)::text)))
     LEFT JOIN public.branch bb ON (((t.beneficiary_id)::text = (bb.id)::text)))
     LEFT JOIN public.profile pbb ON (((bb.profile_id)::text = (pbb.id)::text)))
     LEFT JOIN public.employee eb ON (((t.beneficiary_id)::text = (eb.id)::text)))
     LEFT JOIN public.profile pb ON (((eb.profile_id)::text = (pb.id)::text)))
     LEFT JOIN public.customer c ON (((t.beneficiary_id)::text = (c.id)::text)))
     LEFT JOIN public.profile pc ON (((c.profile_id)::text = (pc.id)::text)));


ALTER VIEW public.transaction_view OWNER TO postgres;

